function fetchData(success) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (success) {
        resolve("Data loaded successfully!");
      } else {
        reject("Error: Failed to load data.");
      }
    }, 1000);
  });
}

fetchData(false)
  .then(data => {
    console.log(data);
  })
  .catch(error => {
    console.error(error); // This will run because the promise was rejected
  });

async function load() {
  try {
    const data = await fetchData(false);
    console.log(data);
  } catch (error) {
    console.error(error); // Catch and handle the error here
  }
}

load();

type User = {
  id: number;
  name: string;
  age: number;
};

// Mapped type that makes every property optional
type PartialUser = {
  [P in keyof User]?: User[P];
};

type Stringify<T> = {
  [P in keyof T]: string;
};

type UserAsStrings = Stringify<User>;
// UserAsStrings is { id: string; name: string; age: string; }

type Mutable<T> = {
  -readonly [P in keyof T]: T[P];
};

// Removes readonly modifier from all properties

type DeepPartial<T> = {
  [P in keyof T]?: T[P] extends object ? DeepPartial<T[P]> : T[P];
};

